    UINavigationController *navVC = rootVC.childViewControllers[0];
    NSParameterAssert([navVC isKindOfClass:[UINavigationController class]]);
    WBHomeViewController *homeVC = navVC.childViewControllers[0];
    NSParameterAssert([homeVC isKindOfClass:[WBHomeViewController class]]);
    return [homeVC isKindOfClass:[WBHomeViewController class]] ? homeVC : nil;
}

