#import "WBVAppResDownloadManager.h"
#import "WBStorageManager.h"
#import "WBAppManager.h"
#import "WBVAppManager.h"
#import "WBVAppManager+Internal.h"

@interface WBVAppResDownloadManager() <NSURLSessionDownloadDelegate>

@property(strong, nonatomic) NSMutableDictionary<NSString *, id> *downloadCompletionHandler;

@property(weak, nonatomic) NSURLSessionDownloadTask *downloadTask;
@property(strong, nonatomic) NSURLSession *session;
@property(assign, nonatomic) CFAbsoluteTime downloadStartTime;
@property(assign, nonatomic) int tryCount;
@property(assign, nonatomic) BOOL noCompleteWithError;

@end

@implementation WBVAppResDownloadManager

// 错误域常量
static NSString *const WBErrorDomainHTTP = @"HTTP";
static NSString *const WBErrorDomainSecurity = @"Security";
static NSString *const WBErrorDomainResDownload = @"ResDownloadDomain";

+ (instancetype)sharedManager {
    static id instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[WBVAppResDownloadManager alloc] init];
    });
    return instance;
}

- (instancetype)init {
    if (self = [super init]) {
        _downloadQueue = [NSMutableArray array];
        _downloadCompletionHandler = [NSMutableDictionary dictionary];
        [self doTimelyCheck];
        _session = [NSURLSession sessionWithConfiguration:NSURLSessionConfiguration.defaultSessionConfiguration delegate:self delegateQueue:[NSOperationQueue mainQueue]];
        // 注册监听器
        [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleDeleteNotification:) name:WBDeleteDownloadResCancelNotification object:nil];
    }
    return self;
}

- (void)dealloc {
    // 取消注册监听器
    [[NSNotificationCenter defaultCenter] removeObserver:self name:WBDeleteDownloadResCancelNotification object:nil];
}

- (BOOL)isDownloading {
    if (_downloadTask && _downloadingVApp) {
        return TRUE;
    }
    return FALSE;
}


- (void)onEnterBackground {
    // if background mode's not enabled and the task's resumable, then save the task
}

- (void)onAppWillTerminate {
    if ([self isDownloading]) {
        // try to save the task
        [self cancelDownloadingTaskByProducingResumeData];
    }
}

- (void)doTimelyCheck {
    dispatch_after(dispatch_time_delay(1.0), dispatch_get_main_queue(), ^{
        [self checkDownloadQueue];
    });
}

- (void)checkDownloadQueue {
    if (_downloadTask == nil) {
        if ([_downloadQueue count] > 0) {
            if (!_downloadingVApp) {
                _downloadingVApp = _downloadQueue.firstObject;
                [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceWaitingDownload forVApp:_downloadingVApp];
                _downloadingVApp.progress = 0.0f;
                _tryCount = 0;
            }

            switch (_downloadingVApp.status) {

                case WBVappStatusResourceWaitingDownload:
                    if (_tryCount >= 3) {
                        [self handleDownloadGiveUp];
                    } else {
//                        _downloadingVApp.versionInfo.resURL = @"http://127.0.0.1/testError.bin";
                        _downloadTask = [_session downloadTaskWithURL:[NSURL URLWithString:_downloadingVApp.versionInfo.resURL]];
                        [_downloadTask resume];
                        _downloadStartTime = CFAbsoluteTimeGetCurrent();
                        [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloading forVApp:_downloadingVApp];
                        [WBEventManager logVappResDownloadEvent:_downloadingVApp];
                    }
                    break;

                case WBVappStatusResourceDownloaded: {
                    [_downloadQueue popFirstObject];
                    void (^downloadCompletionHandler)(void) = self.downloadCompletionHandler[_downloadingVApp.bundleId];
                    if (downloadCompletionHandler) {
                        downloadCompletionHandler();
                        [self.downloadCompletionHandler removeObjectForKey:_downloadingVApp.bundleId];
                    }
                    [[WBStorageManager sharedManager] unzipRes:_downloadingVApp];
                    _downloadingVApp = nil;
                    break;
                }

                case WBVappStatusResourceDownloadError:
                    @synchronized (self) {
                        _tryCount += 1;
                    }
                    [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceWaitingDownload forVApp:_downloadingVApp];
                    _downloadingVApp.progress = 0.0f;
                    break;

                case WBVappStatusResourceDownloadInterrupted: {
                    if (_tryCount >= 3) {
                        [self handleDownloadGiveUp];
                        break;
                    }
                    if (UIApplication.sharedApplication.applicationState == UIApplicationStateActive) {
                        NSData *resumeData = [WBStorageManager.sharedManager loadResumableDataForURL:_downloadingVApp.versionInfo.resURL];
                        if (resumeData) {
                            if (!_downloadStartTime) {
                                _downloadStartTime = CFAbsoluteTimeGetCurrent();
                            }
                            _downloadTask = [_session downloadTaskWithResumeData:resumeData];
                            [_downloadTask resume];
                            NSLog(@"Resource download: resume");
                            [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloading forVApp:_downloadingVApp];
                        } else {
                            [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloadError forVApp:_downloadingVApp];
                            [[WBVAppManager sharedManager] saveError:WBVappStatusResourceDownloadError
                                                         errorDomain:WBErrorDomainResDownload
                                                          errorCode:10001
                                                       errorMessage:@"Download interrupted and cannot be resumed due to missing resume data"
                                                           forVApp:_downloadingVApp];
                        }
                    }
                    break;
                }
                default:
                    break;
            }
        }
    }
    [self doTimelyCheck];
}

- (void)handleDownloadGiveUp {
    [_downloadQueue removeObject:_downloadingVApp];
    [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloadGiveUp
                                    forVApp:_downloadingVApp];
    NSString *bundleId = _downloadingVApp.bundleId;
    void (^completionHandler)(void) = self.downloadCompletionHandler[bundleId];
    if (completionHandler) {
        completionHandler();
        [self.downloadCompletionHandler removeObjectForKey:bundleId];
    }
    if (_downloadTask) {
        [_downloadTask cancel];
        _downloadTask = nil;
    }
    _downloadStartTime = 0;
    _downloadingVApp = nil;
    _tryCount = 0;
    NSLog(@"Resource download: too many retries, give up");
}

- (void)setVAppDownloadPriorityInQueue:(WBVAppModel *)vapp index:(unsigned int)index {
    NSParameterAssert([_downloadQueue containsObject:vapp]);
    if (index == 0) {
        if ([_downloadingVApp isEqual:vapp]) return;
        if (_downloadTask) {
            NSParameterAssert(_downloadingVApp && _downloadingVApp == _downloadQueue.firstObject);
            [self cancelDownloadingTaskByProducingResumeData];
            [_downloadQueue removeFirstObject];
            [_downloadQueue addObject:_downloadingVApp];
            _downloadingVApp = nil;
        }
        return;
    }
    [_downloadQueue removeObject:vapp];
    [_downloadQueue insertObject:vapp atIndex:index];
}


- (BOOL)addToDownloadQueue:(WBVAppModel *)vapp {
    [_downloadQueue addObject:vapp];
    [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceWaitingDownload forVApp:vapp];
    vapp.progress = 0.0f;
    return TRUE;
}


#pragma mark - NSURLSessionDataDelegate

- (void)URLSession:(NSURLSession *)session downloadTask:(NSURLSessionDownloadTask *)downloadTask
      didWriteData:(int64_t)bytesWritten
 totalBytesWritten:(int64_t)totalBytesWritten
totalBytesExpectedToWrite:(int64_t)totalBytesExpectedToWrite {
    if (downloadTask != self.downloadTask) {
        return;
    }
    float newProgress = (CGFloat)totalBytesWritten/(CGFloat)totalBytesExpectedToWrite;
    if (fabs(newProgress - _downloadingVApp.progress) > 0.001) {
        _downloadingVApp.progress = newProgress;
        [_downloadingVApp setInMemoryStatus:WBVappStatusResourceDownloading];
        NSLog(@"downloading res: %f", newProgress);
    }
}

- (void)handleDeleteNotification:(NSNotification *)notification {
    // 接收到删除通知后，取消下载任务
    if (_downloadTask) {
        [_downloadTask cancel];
        NSLog(@"Download task cancelled due to delete notification.");
        [_downloadingVApp setInMemoryStatus:WBVappStatusNone];
        self.noCompleteWithError = YES;

        _downloadTask = nil;    // 重置下载任务
        _downloadStartTime = 0; // 清空下载开始时间
        [_downloadQueue removeAllObjects];  // 清空下载队列
        _downloadingVApp = nil; // 清空当前下载的 VApp
        [self.downloadCompletionHandler removeAllObjects];  // 清空所有下载完成处理器
    }
}

- (void)URLSession:(NSURLSession *)session downloadTask:(NSURLSessionDownloadTask *)downloadTask didFinishDownloadingToURL:(NSURL *)location {
    if (downloadTask != self.downloadTask) {
        return;
    }
    CFAbsoluteTime timeCost = CFAbsoluteTimeGetCurrent() - _downloadStartTime;
    NSHTTPURLResponse *resp = (NSHTTPURLResponse *)downloadTask.response;
    if (!(resp.statusCode >= 200 && resp.statusCode < 299)) {
        NSLog(@"Resource download: unexpected download error: code %zd", resp.statusCode);
        [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloadError forVApp:_downloadingVApp];
        [[WBVAppManager sharedManager] saveError:WBVappStatusResourceDownloadError
                                     errorDomain:WBErrorDomainHTTP
                                      errorCode:resp.statusCode
                                   errorMessage:[NSString stringWithFormat:@"HTTP %zd: Server rejected download request", resp.statusCode]
                                       forVApp:_downloadingVApp];
        [WBEventManager logVappResDownloadResultEvent:_downloadingVApp result:[NSString stringWithFormat:@"response code error %zd", resp.statusCode] timeCost:timeCost];
        return;
    }
    if (location == nil) {
        NSLog(@"Resource download: unknown download error occur");
        [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloadError forVApp:_downloadingVApp];
        [[WBVAppManager sharedManager] saveError:WBVappStatusResourceDownloadError
                                     errorDomain:NSPOSIXErrorDomain
                                      errorCode:-3001   // NSURLErrorCannotOpenFile
                                   errorMessage:@"Downloaded file location is invalid or inaccessible"
                                       forVApp:_downloadingVApp];
        [WBEventManager logVappResDownloadResultEvent:_downloadingVApp result:@"download location error" timeCost:timeCost];
        return;
    }

    NSData *fileData = [NSData dataWithContentsOfURL:location];
    if ([[fileData sha1String] caseInsensitiveCompare:_downloadingVApp.versionInfo.resHash] == 0) {
        NSLog(@"Resource download: hash match");
        if ([WBStorageManager.sharedManager saveRes:_downloadingVApp from:location]) {
            NSLog(@"Resource download: saved");
//            CFAbsoluteTime now = CFAbsoluteTimeGetCurrent();
//            NSInteger cost = (NSInteger)(now-_downloadStartTime);
//            NSLog(@"Download: time cost %zd", cost);
            NSLog(@"Resource download: success");
            [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloaded forVApp:_downloadingVApp];
            [WBEventManager logVappResDownloadResultEvent:_downloadingVApp result:@"0" timeCost:timeCost];
            return;
        }
    } else {
        NSLog(@"Resource download: hash error");
        [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloadError forVApp:_downloadingVApp];
        [[WBVAppManager sharedManager] saveError:WBVappStatusResourceDownloadError
                                     errorDomain:WBErrorDomainSecurity
                                      errorCode:10002
                                   errorMessage:[NSString stringWithFormat:@"SHA1 mismatch: expected %@, got %@",
                                                 _downloadingVApp.versionInfo.resHash,
                                                 [fileData sha1String]]
                                       forVApp:_downloadingVApp];
        [WBEventManager logVappResDownloadResultEvent:_downloadingVApp result:@"hash error" timeCost:timeCost];
    }
    // 清空下载任务
    _downloadTask = nil;
}

- (void)URLSession:(NSURLSession *)session task:(NSURLSessionTask *)task didCompleteWithError:(NSError *)error {
    if (self.noCompleteWithError) {
        return;
    }
    if (task != self.downloadTask) {
        return;
    }
    if (!error) {
        NSParameterAssert(_downloadingVApp.status == WBVappStatusResourceDownloaded);
        _downloadTask = nil;
        return;
    }
    CFAbsoluteTime timeCost = CFAbsoluteTimeGetCurrent() - _downloadStartTime;
    if ([error.domain isEqualToString:NSURLErrorDomain]) {
        if (error.code == NSURLErrorNetworkConnectionLost) {
            NSLog(@"Resource download: error, connection lost");
        } else if (error.code == NSURLErrorCancelled) {
            NSLog(@"Resource download: error, manually cancelled");
        }
        NSData *resumeData = error.userInfo[NSURLSessionDownloadTaskResumeData];
        [self handleProcessingResumeData:resumeData];
    } else {
        NSLog(@"Resource download: unexpected error occured..");
        [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloadError forVApp:_downloadingVApp];
        [[WBVAppManager sharedManager] saveError:WBVappStatusResourceDownloadError
                                     errorDomain:error.domain
                                      errorCode:error.code
                                   errorMessage:error.localizedDescription
                                       forVApp:_downloadingVApp];
        [WBEventManager logVappResDownloadResultEvent:_downloadingVApp result:error.description timeCost:timeCost];
    }
    _downloadTask = nil;
}

- (void)addDownloadCompletionHandler:(void (^)(void))completionHandler toVApp:(WBVAppModel *)vapp {
    NSArray<NSString *> *downloadingBundleIds = [self.downloadQueue valueForKey:NSStringFromSelector(@selector(bundleId))];
    if (![downloadingBundleIds containsObject:vapp.bundleId]) return;
    self.downloadCompletionHandler[vapp.bundleId] = completionHandler;
}

#pragma mark - private

- (void)cancelDownloadingTaskByProducingResumeData {
    NSParameterAssert(_downloadTask);
    [_downloadTask cancelByProducingResumeData:^(NSData * _Nullable resumeData) {
        [self handleProcessingResumeData:resumeData];
    }];
}

- (void)handleProcessingResumeData:(NSData *)resumeData {
    CFAbsoluteTime timeCost = CFAbsoluteTimeGetCurrent() - _downloadStartTime;
    if (resumeData == nil) {
        NSLog(@"Resource download: interrupted, unable to produce resumable data");
        [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloadError forVApp:self.downloadingVApp];
        [[WBVAppManager sharedManager] saveError:WBVappStatusResourceDownloadError
                                     errorDomain:NSURLErrorDomain
                                      errorCode:-3006  // NSURLErrorDownloadDecodingFailedMidStream
                                   errorMessage:@"Resume data generation failed: download decoding interrupted"
                                       forVApp:self.downloadingVApp];
        [WBEventManager logVappResDownloadResultEvent:self.downloadingVApp result:@"interrupted, data not resumed" timeCost:timeCost];
        return;
    }
    [WBStorageManager.sharedManager saveResumableData:resumeData forURL:self.downloadingVApp.versionInfo.resURL];
    NSLog(@"Resource download: interrupted, save resume data");
    self.downloadTask = nil;

    @synchronized (self) {
        _tryCount += 1;
    }
    [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloadInterrupted forVApp:self.downloadingVApp];
    [WBEventManager logVappResDownloadResultEvent:self.downloadingVApp result:@"interrupted, data resumed" timeCost:timeCost];
}

@end

