- (BOOL)hasRes:(WBVAppModel *)vapp ofSha1Hash:(NSString*)hash {
    if (vapp.versionInfo.resHash == nil) {
        return FALSE;
    }
    NSString *path = [self getResCachePath:vapp];
    if ([NSFileManager.defaultManager fileExistsAtPath:path] == TRUE) {
        NSData *fileData = [NSData dataWithContentsOfFile:path];
        if ([fileData.sha1String isEqualToString:hash]) {
            return TRUE;
        }
    }
    return FALSE;
}

- (void)unzipRes:(WBVAppModel *)vapp {
    [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceInstalling forVApp:vapp];
    CFAbsoluteTime unzipStartTime = CFAbsoluteTimeGetCurrent();
    [WBEventManager logVappResUnzipEvent:vapp];
    void (^completionHandler)(NSString * _Nullable dest) = self.unzipResCompletionHandler[vapp.bundleId];
    NSString *path = [self getResCachePath:vapp];
    if (![NSFileManager.defaultManager fileExistsAtPath:path]) {
        [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceInstallError forVApp:vapp];
        [[WBVAppManager sharedManager] saveError:WBVappStatusResourceInstallError
                                     errorDomain:NSCocoaErrorDomain
                                       errorCode:4  // NSFileNoSuchFileError
                                    errorMessage:@"Resource file not found at specified path"
                                         forVApp:vapp];
        if (completionHandler) {
            completionHandler(nil);
        }
        return;
    }
    __block NSString *dest = [self getUnzipResTmpPath:vapp];
    // 这里修改为：每次安装之后都将临时文件夹删除，也就不会再查看这个文件夹是否存在，而跳过解压缩过程了
    ////    [NSFileManager.defaultManager removeItemAtPath:dest error:nil];
    //    if ([NSFileManager.defaultManager fileExistsAtPath:dest]) {
    //        [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceInstalled forVApp:vapp];
    //        if (completionHandler) {
    //            completionHandler(dest);
    //        }
    //        return;
    //    }

    vapp.progress = 0;
    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
        [SSZipArchive unzipFileAtPath:path toDestination:dest progressHandler:^(NSString * _Nonnull entry, unz_file_info zipInfo, long entryNumber, long total) {
            [NSThread wb_executeOnMainThread:^{
                CGFloat progress = ((CGFloat)entryNumber)/(total+1);
                if (progress > 0.01 + vapp.progress) {
                    vapp.progress = progress;
                    [vapp setInMemoryStatus:WBVappStatusResourceInstalling];
                    NSLog(@"unzipping res: %f", progress);
                }
            }];
        } completionHandler:^(NSString * _Nonnull path, BOOL succeeded, NSError * _Nonnull error) {
            [NSThread wb_executeOnMainThread:^{
                NSParameterAssert(succeeded ^ (error != nil));
                if (error) {
                    [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceInstallError forVApp:vapp];
                    [[WBVAppManager sharedManager] saveError:WBVappStatusResourceInstallError
                                                 errorDomain:error.domain
                                                   errorCode:error.code
                                                errorMessage:error.localizedDescription
                                                     forVApp:vapp];
                    dest = nil;
                } else if (succeeded) {
                    vapp.userInfo.resUnzipPath = dest;
                    [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceInstalled forVApp:vapp];
                    [self markResUnzipCompletedAtPath:dest];
                    BOOL hasUICallback = (self.unzipResCompletionHandler[vapp.bundleId] != nil);
                    if (!hasUICallback) {
                        [[WBVAppManager sharedManager] initVApp:vapp resPath:dest callback:^{
                            [self cleanUpResTmpPath:dest];
                        }];
                    }
                }
                [WBUtility calculateSHA1ForFolder:vapp.userInfo.resUnzipPath includeSubdirectories:YES completion:^(NSString * _Nonnull sha1, NSError * _Nonnull error) {
                    NSDictionary *data = @{
                        @"usingResHash": sha1 ?: error.description,
                    };
                    [WBEventManager logVappUsingResHashRecord:data];
                    if (!error) {
                        [self markResSHA1CompletedAtPath:vapp.userInfo.resUnzipPath];
                    }
                }];

                [WBEventManager logVappResUnzipResultEvent:vapp result:succeeded ? @"0" : error.description timeCost:CFAbsoluteTimeGetCurrent() - unzipStartTime];
                void (^completionHandler)(NSString * _Nullable dest) = self.unzipResCompletionHandler[vapp.bundleId];
                if (completionHandler) completionHandler(dest);
            }];
        }];
    });
}


- (NSString*)unzipLocalize:(NSData*)zipData {
    NSString *randomFileName = [[NSProcessInfo processInfo] globallyUniqueString];
    NSString *randomFile = [_tmpRoot stringByAppendingPathComponent:randomFileName];
    if ([zipData writeToFile:randomFile atomically:true] == FALSE) {
        return nil;
    }
    NSString *randomUnzipDirName = [[NSProcessInfo processInfo] globallyUniqueString];
    NSString *randomUnzipDir = [_tmpRoot stringByAppendingPathComponent:randomUnzipDirName];
    [NSFileManager.defaultManager removeItemAtPath:randomUnzipDir error:nil];
    if([SSZipArchive unzipFileAtPath:randomFile toDestination:randomUnzipDir]) {
        return randomUnzipDir;
    }
    return nil;
}

- (NSMutableDictionary *)stateForPath:(NSString *)path createIfNeeded:(BOOL)create {
    if (path.length == 0) return nil;
    NSMutableDictionary *state = self.resCleanupStates[path];
    if (!state && create) {
        state = [@{ @"unzipDone": @NO, @"sha1Done": @NO, @"cleanupRequested": @NO } mutableCopy];
        self.resCleanupStates[path] = state;
    }
    return state;
}

- (void)markResUnzipCompletedAtPath:(NSString *)path {
    NSMutableDictionary *state = [self stateForPath:path createIfNeeded:YES];
    if (!state) return;
    state[@"unzipDone"] = @YES;
    [self tryPerformResCleanupAtPath:path];
}

- (void)markResSHA1CompletedAtPath:(NSString *)path {
    NSMutableDictionary *state = [self stateForPath:path createIfNeeded:YES];
    if (!state) return;
    state[@"sha1Done"] = @YES;
    [self tryPerformResCleanupAtPath:path];
}

- (void)requestResCleanupAtPath:(NSString *)path {
    NSMutableDictionary *state = [self stateForPath:path createIfNeeded:YES];
    if (!state) return;
    state[@"cleanupRequested"] = @YES;
}

- (void)tryPerformResCleanupAtPath:(NSString *)path {
    NSMutableDictionary *state = [self stateForPath:path createIfNeeded:NO];
    if (!state) return;
    BOOL cleanupRequested = [state[@"cleanupRequested"] boolValue];
    BOOL unzipDone = [state[@"unzipDone"] boolValue];
    BOOL sha1Done = [state[@"sha1Done"] boolValue];
    if (cleanupRequested && unzipDone && sha1Done) {
        NSFileManager *fileManager = [NSFileManager defaultManager];
        NSError *error = nil;
        if ([fileManager fileExistsAtPath:path]) {
            [fileManager removeItemAtPath:path error:&error];
        }
        [self.resCleanupStates removeObjectForKey:path];
    }
}

- (void)cleanUpResTmpPath:(NSString *)tmpPath {
    [self requestResCleanupAtPath:tmpPath];
    [self tryPerformResCleanupAtPath:tmpPath];
}

- (void)addUnzipResCompletionHandler:(void (^)(NSString * _Nullable dest))completionHandler toVApp:(WBVAppModel *)vapp {
    self.unzipResCompletionHandler[vapp.bundleId] = completionHandler;
}

